<template>
    <div class="browser-box">
        <a-popover placement="left" trigger="hover" class="browser-icon" @visibleChange="visibleChange1($event)">
            <template #content>
                <div id="qrcode-box"></div>
            </template>
            <MobileOutlined :style="{ fontSize: '36px', color: '#08c' }" />
        </a-popover>

        <WechatOutlined class="browser-icon" :style="{ fontSize: '36px', color: '#08c' }" />
        <CodepenOutlined class="browser-icon" :style="{ fontSize: '36px', color: '#08c' }" />
    </div>
</template>
<script>
import { MobileOutlined, WechatOutlined, CodepenOutlined } from "@ant-design/icons-vue";
import QRCode from "qrcodejs2";

export default {
    components: {
        MobileOutlined,
        WechatOutlined,
        CodepenOutlined
    },
    setup() {
        const qrcode = link => {
            new QRCode("qrcode-box", {
                width: 100, // 二维码宽度，单位像素
                height: 100, // 二维码高度，单位像素
                text: link // 生成二维码的链接
            });
        };
        const visibleChange1 = visible => {
            if (visible) {
                setTimeout(() => {
                    qrcode("https://www.baidu.com");
                });
            } else {
                let dom = document.getElementById("qrcode-box");
                dom.innerHTML = "";
            }
        };
        return {
            qrcode,
            visibleChange1
        };
    }
};
</script>

<style lang="scss" scoped>
.browser-box {
    position: fixed;
    top: 50%;
    right: 16px;
    display: flex;
    flex-direction: column;
    z-index: 3;

    .browser-icon {
        margin-top: 16px;
        cursor: pointer;

        &:first-of-type {
            margin-top: 0;
        }
    }

    #qrcode-box {
        right: 20px;
        width: 100px;
        height: 100px;
        z-index: 3;
    }
}
</style>
