<template>
    <div class="home-wrapper">
        <particles-bg class="particles-bg" type="cobweb" :bg="true" />
        <view-box></view-box>
        <div class="banner">
            <!-- Mr.H's blog -->
            <svg style="width:100%;height:100%" viewBox="0 0 550 300">
                <text x="0" y="70%">Mr.H's blog</text>
            </svg>
        </div>
        <div class="home-content">
            <a-skeleton active v-if="!articleList.length" style="width:820px" />
            <div class="article-list" v-if="articleList.length">
                <div v-for="(item, index) in articleList" :key="index" class="list-item" @click="viewArticle(item)">
                    <div class="title">{{ item.title }}</div>
                    <div class="info">
                        <UserOutlined style="margin-right:5px" />
                        <div>{{ item.author }}</div>
                        <ClockCircleOutlined style="margin-right:5px;margin-left:16px" />
                        <div>{{ item.createTime }}</div>
                        <TagOutlined style="margin-right:5px;margin-left:16px" />
                        <div v-if="item.tags">{{ item.tags }}</div>
                    </div>
                </div>
                <a-pagination style="margin-top:16px" v-model:current="params.pageNumber" :total="totalRecords" />
            </div>
            <div class="info-wrapper">
                <div class="personal-wrapper">
                    <img :src="store.state.userInfo.avatar" class="avatar" />
                    <div class="username">{{ store.state.userInfo.nickname }}</div>
                    <div class="count-box">
                        <div class="count-item">
                            <div class="num">{{ totalRecords }}</div>
                            <div>Article</div>
                        </div>
                        <div class="divider"></div>
                        <div class="count-item">
                            <div class="num">{{ totalTags }}</div>
                            <div>Tag</div>
                        </div>
                    </div>
                </div>
                <div class="tag-wrapper">
                    <div class="tag-title">
                        <TagOutlined style="margin-right:16px" />
                        <div>Tag</div>
                    </div>
                    <div class="tag-content">
                        <div v-for="(item, index) in tagList" :key="index" class="tag-item" :style="{ background: item.color }">{{ item.name }}</div>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import { reactive, inject, onMounted, ref } from "vue";
import { useStore } from "vuex";
import { useRouter } from "vue-router";
import { Utils } from "../utils/utils";
import { UserOutlined, ClockCircleOutlined, TagOutlined } from "@ant-design/icons-vue";
import { ParticlesBg } from "particles-bg-vue";
import ViewBox from "../components/ViewBox";

export default {
    components: {
        UserOutlined,
        ClockCircleOutlined,
        TagOutlined,
        ParticlesBg,
        ViewBox
    },
    setup() {
        const $api = inject("$api");
        const store = useStore();
        const router = useRouter();

        let articleList = ref([]);
        let tagList = ref([]);
        const totalRecords = ref(0);
        const totalTags = ref(0);
        const params = reactive({
            pageSize: 10,
            pageNumber: 1
        });

        // 获取文章列表
        const getArticleList = () => {
            articleList.value = [];
            $api.article.getArticleList(params).then(res => {
                articleList.value = res.data.datas;
                totalRecords.value = res.data.totalRecords;
            });
        };

        // 获取Taglist
        const getTagList = () => {
            tagList.value = [];
            $api.article.getAllTags().then(res => {
                res.data.forEach(item => {
                    tagList.value.push({
                        name: item,
                        color: Utils.getTagColor()
                    });
                });
                tagList.value.unshift({
                    name: "All",
                    color: Utils.getTagColor()
                });
                totalTags.value = tagList.value.length - 1;
            });
        };

        const viewArticle = data => {
            store.commit("setCurWritingArticleId", data.id);
            router.push({ path: "/note" });
        };

        onMounted(() => {
            store.commit("setCurWritingArticleId", null);
            getArticleList();
            getTagList();
            // qrcode("https://hjdbenny.gitee.io/blog/#/home");
        });
        return {
            params,
            totalRecords,
            articleList,
            viewArticle,
            store,
            tagList,
            totalTags
        };
    }
};
</script>

